import torch
import torch.nn as nn
from torch.utils.cpp_extension import load_inline

# Define robust custom CUDA kernel for optimized matrix multiplication
matmul_optimized_source = """
#include <torch/extension.h>
#include <cuda_runtime.h>
#include <cublas_v2.h>
#include <cassert>

// Kernel for transposing matrix A (K, M) -> (M, K) using 1D indexing
__global__ void transpose_A_kernel(const float* A, float* A_T, int K, int M, int total_threads) {
    int tid = blockIdx.x * blockDim.x + threadIdx.x;

    // Process multiple elements per thread for efficiency
    for (int idx = tid; idx < M * K; idx += total_threads) {
        int row = idx / K;  // row in A_T (0..M-1)
        int col = idx % K;  // col in A_T (0..K-1)

        // Convert to coordinates in original A
        int original_row = col;  // row in A (0..K-1)
        int original_col = row;  // col in A (0..M-1)

        // Single bounds check for both input and output
        if (original_row < K && original_col < M && row < M && col < K) {
            A_T[row * K + col] = A[original_row * M + original_col];
        }
    }
}

// Kernel for transposing matrix B (N, K) -> (K, N) using 1D indexing
__global__ void transpose_B_kernel(const float* B, float* B_T, int N, int K, int total_threads) {
    int tid = blockIdx.x * blockDim.x + threadIdx.x;

    // Process multiple elements per thread for efficiency
    for (int idx = tid; idx < K * N; idx += total_threads) {
        int row = idx / N;  // row in B_T (0..K-1)
        int col = idx % N;  // col in B_T (0..N-1)

        // Convert to coordinates in original B
        int original_row = col;  // row in B (0..N-1)
        int original_col = row;  // col in B (0..K-1)

        // Single bounds check for both input and output
        if (original_row < N && original_col < K && row < K && col < N) {
            B_T[row * N + col] = B[original_row * K + original_col];
        }
    }
}

torch::Tensor matmul_optimized_cuda(torch::Tensor A, torch::Tensor B) {
    // Get dimensions
    int K = A.size(0);
    int M = A.size(1);
    int N = B.size(0);

    // Validate dimensions
    assert(A.size(0) == B.size(1));

    // Create output tensor
    auto C = torch::zeros({M, N}, A.options());

    // Create transposed versions
    auto A_T = torch::zeros({M, K}, A.options());
    auto B_T = torch::zeros({K, N}, B.options());

    // Configure 1D thread blocks for transpose kernels
    const int threads_per_block = 256;

    // Launch transpose_A_kernel with enough threads to cover all elements
    int total_elements_A = M * K;
    int blocks_A = (total_elements_A + threads_per_block - 1) / threads_per_block;
    transpose_A_kernel<<<blocks_A, threads_per_block>>>(
        A.data_ptr<float>(),
        A_T.data_ptr<float>(),
        K, M,
        blocks_A * threads_per_block
    );

    // Launch transpose_B_kernel with enough threads to cover all elements
    int total_elements_B = K * N;
    int blocks_B = (total_elements_B + threads_per_block - 1) / threads_per_block;
    transpose_B_kernel<<<blocks_B, threads_per_block>>>(
        B.data_ptr<float>(),
        B_T.data_ptr<float>(),
        N, K,
        blocks_B * threads_per_block
    );

    // Use cuBLAS for matrix multiplication: C = A_T * B_T
    cublasHandle_t handle;
    cublasCreate(&handle);

    const float alpha = 1.0f;
    const float beta = 0.0f;

    cublasSgemm(handle,
                CUBLAS_OP_N, CUBLAS_OP_N,
                N, M, K,  // Note: dimensions are swapped for column-major
                &alpha,
                B_T.data_ptr<float>(), N,
                A_T.data_ptr<float>(), K,
                &beta,
                C.data_ptr<float>(), N);

    cublasDestroy(handle);

    return C;
}
"""

matmul_optimized_cpp_source = """
torch::Tensor matmul_optimized_cuda(torch::Tensor A, torch::Tensor B);
"""

# Compile the inline CUDA code
matmul_optimized = load_inline(
    name="matmul_optimized",
    cpp_sources=matmul_optimized_cpp_source,
    cuda_sources=matmul_optimized_source,
    functions=["matmul_optimized_cuda"],
    verbose=False,
    extra_cflags=["-O3"],
    extra_ldflags=["-lcublas"],
)

class ModelNew(nn.Module):
    """
    Optimized model with custom CUDA kernel for matrix multiplication
    """
    def __init__(self):
        super(ModelNew, self).__init__()
        self.matmul_optimized = matmul_optimized

    def forward(self, A: torch.Tensor, B: torch.Tensor) -> torch.Tensor:
        """
        Performs optimized matrix multiplication A.T * B.T

        Args:
            A: Input tensor of shape (K, M).
            B: Input tensor of shape (N, K).

        Returns:
            Output tensor of shape (M, N).
        """
        return self.matmul_optimized.matmul_optimized_cuda(A, B)
